
#include "svg_helper.h"
int main(){string stem="08_quick_sort_partition",title="08 Quick Sort Partition"; vector<vector<int>> frames={{5,3,8,1,4,7},{5,3,8,1,4,7},{5,3,1,8,4,7},{5,3,1,4,8,7},{4,3,1,5,8,7},{4,3,1,5,7,8},{1,3,4,5,7,8},{1,3,4,5,7,8}}; vector<int> L={0,1,2,3,0,4,0,0}, R={4,4,3,4,4,5,2,2}, P={5,5,5,5,3,3,3,3}; vector<string> f={"choose pivot","move i and j pointers","swap wrong-side keys","place pivot between partitions"}; for(int k=0;k<frames.size();++k){int W=1140,H=680; set<int> hot={L[k],R[k]}, piv={P[k]}, done; if(k>=4) done.insert(P[k]); string s=startSVG(W,H,title,"Step "+to_string(k+1)+" / "+to_string(frames.size())+" - partition around pivot"); s+=box(50,120,610,400,"#fff","#bfd3e6"); s+=T(90,155,"Quick sort partition: pivot separates <= pivot and >= pivot",17,"#123","700"); s+=arr(frames[k],90,220,hot,done,piv); s+=T(90+L[k]*58+15,205,"i",18,"#dc2626","700"); s+=T(90+R[k]*58+15,305,"j",18,"#dc2626","700"); s+=T(90+P[k]*58+4,185,"pivot",15,"#b45309","700"); s+=arrow(90+L[k]*58+29,330,90+R[k]*58+29,330,"#d92d27",4); s+=box(90,385,190,60,"#dcfce7","#16a34a")+T(112,420,"<= pivot side",16,"#166534","700"); s+=box(360,385,190,60,"#fee2e2","#ef4444")+T(382,420,">= pivot side",16,"#991b1b","700"); s+=sidebar(k+1,frames.size(),f)+footer(W,H,stem+".cpp"); stringstream p; p<<"output/"<<stem<<"_steps/step_"<<setw(2)<<setfill('0')<<k+1<<".svg"; writeFile(p.str(),s+endSVG());}}
